# If your goal is a real linked list
Here’s a minimal singly linked list:

```javascript
class Node {
    constructor(value) {
        this.value = value;
        this.next = null;
    }
}

class LinkedList {
    constructor() {
        this.head = null;
        this.tail = null;
        this.length = 0;
    }

    add(value) {
        const node = new Node(value);

        if (!this.head) {
            this.head = node;
            this.tail = node;
        } else {
            this.tail.next = node;
            this.tail = node;
        }

        this.length++;
        return this;
    }

    get(index) {
        if (!Number.isInteger(index) || index < 0 || index >= this.length) {
            throw new RangeError("Index out of bounds");
        }

        let current = this.head;
        let i = 0;

        while (i < index) {
            current = current.next;
            i++;
        }

        return current.value;
    }

    remove(index) {
        if (!Number.isInteger(index) || index < 0 || index >= this.length) {
            throw new RangeError("Index out of bounds");
        }

        let removed;

        if (index === 0) {
            removed = this.head;
            this.head = this.head.next;

            if (this.length === 1) {
                this.tail = null;
            }
        } else {
            let prev = this.head;
            let i = 0;

            while (i < index - 1) {
                prev = prev.next;
                i++;
            }

            removed = prev.next;
            prev.next = removed.next;

            if (removed === this.tail) {
                this.tail = prev;
            }
        }

        this.length--;
        return removed.value;
    }
}
```

